@page "/privacy"
@attribute [ExcludeFromInteractiveRouting]
@using Microsoft.AspNetCore.Http

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

@if (HasConsented)
{
    <div class="alert alert-success">
        ✓ You have already accepted our cookie policy.
    </div>
}
else
{
    <div class="alert alert-warning">
        You have not yet accepted our cookie policy.
    </div>
}

<h2>How We Use Cookies</h2>
<p>
    This application uses cookies to improve your experience. By using our site,
    you acknowledge that you have read and understand our cookie policy.
</p>

<h2>Data Collection</h2>
<p>
    We collect only the minimum data necessary to provide our services.
    Your personal information is never sold to third parties.
</p>

@code {
    [CascadingParameter]
    private HttpContext? HttpContext { get; set; }

    private bool HasConsented { get; set; }

    protected override void OnInitialized()
    {
        HasConsented = HttpContext?.Request.Cookies.ContainsKey("consent") == true;
    }
}

